from datetime import datetime, timezone


def earliest_event(events):
    if not events:
        raise ValueError("events must not be empty")

    def to_instant(dt):
        if not isinstance(dt, datetime):
            raise TypeError("all events must be datetime instances")
        if dt.tzinfo is None or dt.utcoffset() is None:
            raise ValueError("all events must be timezone-aware datetimes")
        return dt.astimezone(timezone.utc)

    earliest = events[0]
    earliest_instant = to_instant(earliest)
    for event in events[1:]:
        instant = to_instant(event)
        if instant < earliest_instant:
            earliest = event
            earliest_instant = instant
    return earliest
```

