from datetime import datetime
from zoneinfo import ZoneInfo


def elapsed_seconds(start_naive, end_naive, zone):
    tz = ZoneInfo(zone)

    def to_utc(dt):
        # Attach zone, using fold=0 for the earlier occurrence on ambiguous times
        aware = dt.replace(tzinfo=tz, fold=0)
        return aware.astimezone(ZoneInfo("UTC"))

    start_utc = to_utc(start_naive)
    end_utc = to_utc(end_naive)

    return abs((end_utc - start_utc).total_seconds())
```

