import datetime


def parse_us_date(s):
    parts = s.strip().split('/')
    if len(parts) != 3:
        raise ValueError(f"Invalid US date format: {s!r}")

    month_str, day_str, year_str = parts

    try:
        month = int(month_str)
        day = int(day_str)
        year = int(year_str)
    except ValueError:
        raise ValueError(f"Invalid US date format: {s!r}")

    if not (1 <= month <= 12):
        raise ValueError(f"Month out of range in {s!r}: {month}")

    # datetime.date validates day-of-month, including leap days
    # (e.g. Feb 29 only allowed in leap years).
    try:
        return datetime.date(year, month, day)
    except ValueError as exc:
        raise ValueError(f"Invalid US date {s!r}: {exc}")
```

