from datetime import datetime, timedelta, timezone
from operator import index
from zoneinfo import ZoneInfo


def add_days_keep_wall(naive, zone, n):
    if not isinstance(naive, datetime):
        raise TypeError("naive must be a datetime.datetime")
    if naive.tzinfo is not None and naive.utcoffset() is not None:
        raise ValueError("naive must be timezone-naive")

    days = index(n)

    if isinstance(zone, ZoneInfo):
        z = zone
    elif isinstance(zone, str):
        z = ZoneInfo(zone)
    else:
        raise TypeError("zone must be an IANA time zone name or zoneinfo.ZoneInfo")

    target_date = naive.date() + timedelta(days=days)
    target = datetime.combine(target_date, naive.time()).replace(fold=0)

    def valid_with_fold(fold):
        aware = target.replace(tzinfo=z, fold=fold)
        round_tripped = aware.astimezone(timezone.utc).astimezone(z)
        return (
            round_tripped.replace(tzinfo=None) == target
            and round_tripped.fold == fold
        )

    if valid_with_fold(0):
        return target.replace(tzinfo=z, fold=0)

    if valid_with_fold(1):
        return target.replace(tzinfo=z, fold=1)

    zone_name = getattr(z, "key", str(zone))
    raise ValueError(
        f"nonexistent local time in {zone_name}: "
        f"{target.isoformat()} cannot be represented with the same wall-clock time"
    )
