from datetime import timezone


def same_instant(a, b):
    def _aware(dt):
        return dt.tzinfo is not None and dt.utcoffset() is not None

    def _wall_fields(dt):
        return (
            dt.year,
            dt.month,
            dt.day,
            dt.hour,
            dt.minute,
            dt.second,
            dt.microsecond,
        )

    def _existent(dt):
        utc = dt.astimezone(timezone.utc)
        back = utc.astimezone(dt.tzinfo)
        return _wall_fields(back) == _wall_fields(dt)

    def _instant_key(dt):
        offset = dt.utcoffset()
        local_us = (
            (
                (dt.toordinal() * 24 + dt.hour) * 60 + dt.minute
            ) * 60 + dt.second
        ) * 1_000_000 + dt.microsecond
        offset_us = (
            (offset.days * 86_400 + offset.seconds) * 1_000_000
            + offset.microseconds
        )
        return local_us - offset_us

    if not _aware(a) or not _aware(b):
        raise ValueError("same_instant() requires timezone-aware datetimes")

    if not _existent(a) or not _existent(b):
        return False

    return _instant_key(a) == _instant_key(b)
