from datetime import datetime, timezone
from zoneinfo import ZoneInfo


def disambiguate(naive, zone, prefer):
    if not isinstance(naive, datetime):
        raise TypeError("naive must be a datetime")

    if naive.tzinfo is not None and naive.utcoffset() is not None:
        raise ValueError("naive must be timezone-naive")

    if prefer not in {"earlier", "later"}:
        raise ValueError("prefer must be 'earlier' or 'later'")

    tz = ZoneInfo(zone)

    earlier = naive.replace(tzinfo=tz, fold=0)
    later = naive.replace(tzinfo=tz, fold=1)

    def round_trips(dt):
        return (
            dt.astimezone(timezone.utc)
            .astimezone(tz)
            .replace(tzinfo=None)
            == naive
        )

    earlier_valid = round_trips(earlier)
    later_valid = round_trips(later)

    if not (earlier_valid and later_valid and earlier.utcoffset() != later.utcoffset()):
        if not earlier_valid and not later_valid:
            raise ValueError("nonexistent local time")
        raise ValueError("not an ambiguous local time")

    earlier_utc = earlier.astimezone(timezone.utc)
    later_utc = later.astimezone(timezone.utc)

    if prefer == "earlier":
        return earlier if earlier_utc < later_utc else later
    return later if later_utc > earlier_utc else earlier
