from datetime import datetime, timezone
from zoneinfo import ZoneInfo


def disambiguate(naive, zone, prefer):
    if not isinstance(naive, datetime):
        raise TypeError("naive must be a datetime")

    if naive.tzinfo is not None and naive.utcoffset() is not None:
        raise ValueError("naive must be a naive datetime")

    if prefer not in {"earlier", "later"}:
        raise ValueError("prefer must be 'earlier' or 'later'")

    tz = ZoneInfo(zone) if isinstance(zone, str) else zone

    candidates = [
        naive.replace(tzinfo=tz, fold=0),
        naive.replace(tzinfo=tz, fold=1),
    ]

    valid = []
    for candidate in candidates:
        round_tripped = candidate.astimezone(timezone.utc).astimezone(tz)
        if (
            round_tripped.replace(tzinfo=None) == naive
            and round_tripped.fold == candidate.fold
        ):
            valid.append(candidate)

    if len(valid) != 2 or valid[0].utcoffset() == valid[1].utcoffset():
        raise ValueError("the supplied local datetime is not ambiguous in this zone")

    valid.sort(key=lambda dt: dt.astimezone(timezone.utc))
    return valid[0] if prefer == "earlier" else valid[1]
