import calendar
from datetime import date, datetime, timezone, timedelta


def add_one_month(d):
    if not isinstance(d, date):
        raise TypeError("d must be a datetime.date")

    year = d.year + (1 if d.month == 12 else 0)
    month = 1 if d.month == 12 else d.month + 1
    day = min(d.day, calendar.monthrange(year, month)[1])

    result = d.replace(year=year, month=month, day=day)

    if not isinstance(result, datetime) or result.tzinfo is None or result.utcoffset() is None:
        return result

    tz = result.tzinfo
    naive = result.replace(tzinfo=None)

    def valid_folds(naive_dt):
        folds = []
        for fold in (0, 1):
            local = naive_dt.replace(tzinfo=tz, fold=fold)
            back = local.astimezone(timezone.utc).astimezone(tz)
            if back.replace(tzinfo=None) == naive_dt and back.fold == fold:
                folds.append(fold)
        return folds

    folds = valid_folds(naive)
    if folds:
        return result.replace(fold=result.fold if result.fold in folds else folds[0])

    candidates = []
    for fold in (0, 1):
        local = naive.replace(tzinfo=tz, fold=fold)
        back = local.astimezone(timezone.utc).astimezone(tz)
        if back.replace(tzinfo=None) > naive:
            candidates.append(back)

    if candidates:
        return min(candidates, key=lambda x: x.replace(tzinfo=None))

    step = timedelta(minutes=1)
    probe = naive + step
    while not valid_folds(probe):
        step *= 2
        probe = naive + step

    lo = 0
    hi = int((probe - naive).total_seconds() * 1_000_000)

    while lo + 1 < hi:
        mid = (lo + hi) // 2
        mid_naive = naive + timedelta(microseconds=mid)
        if valid_folds(mid_naive):
            hi = mid
        else:
            lo = mid

    final_naive = naive + timedelta(microseconds=hi)
    return final_naive.replace(tzinfo=tz, fold=valid_folds(final_naive)[0])
```

