import zoneinfo
from datetime import datetime, timedelta

def add_days_keep_wall(naive, zone, n):
    """
    Add n calendar days to a naive wall-clock datetime,
    keeping the same wall-clock time in the given IANA timezone.
    Returns a timezone-aware datetime.

    For ambiguous times (fall-back DST), chooses the earlier occurrence.
    For nonexistent times (spring-forward DST), finds the next valid local time.
    """
    if isinstance(zone, str):
        tz = zoneinfo.ZoneInfo(zone)
    else:
        tz = zone

    target_naive = naive + timedelta(days=n)

    try:
        return target_naive.replace(tzinfo=tz)
    except zoneinfo.AmbiguousTimeError:
        # Earlier occurrence corresponds to fold=0
        return target_naive.replace(fold=0, tzinfo=tz)
    except zoneinfo.NonexistentTimeError:
        # Move forward minute by minute until we find a valid local time.
        current = target_naive
        delta = timedelta(minutes=1)
        while True:
            try:
                return current.replace(tzinfo=tz)
            except zoneinfo.NonexistentTimeError:
                current += delta
