from datetime import datetime, timedelta
from zoneinfo import ZoneInfo, NonExistentTimeError

def resolve_nonexistent(naive: datetime, zone: str) -> datetime:
    """Resolve a naive wall-clock datetime to an aware datetime in the given IANA timezone.

    If the wall time exists, attach the timezone and return.
    If it does not exist (spring-forward gap), roll forward until the first existing local time.
    If it is ambiguous (fall-back), use the earlier occurrence (fold=0).
    """
    tz = ZoneInfo(zone)
    # First attempt: use fold=0 to handle both existing and ambiguous times.
    try:
        return naive.replace(tzinfo=tz, fold=0)
    except NonExistentTimeError:
        pass

    # The time is nonexistent -> roll forward minute by minute until it exists.
    step = timedelta(minutes=1)
    current = naive
    while True:
        current += step
        try:
            return current.replace(tzinfo=tz, fold=0)
        except NonExistentTimeError:
            continue
