from zoneinfo import ZoneInfo

def attach_wall_zone(naive, zone):
    zone_info = ZoneInfo(zone)
    try:
        aware = naive.replace(tzinfo=zone_info)
    except ValueError:
        if naive.hour == 0 and naive.minute == 0 and naive.second == 0 and naive.microsecond == 0:
            # It's midnight; try previous day if current day is ambiguous
            prev_day = naive - timedelta(days=1)
            try:
                aware = prev_day.replace(tzinfo=zone_info)
            except ValueError:
                # If still ambiguous on previous day, this shouldn't happen per problem constraints
                # but we raise to be safe for invalid inputs
                raise ValueError("Ambiguous time found and cannot resolve to valid local time")
        else:
            raise ValueError("Ambiguous time found and cannot resolve to valid local time")
    return aware
