from dateutil.relativedelta import relativedelta

def add_years(d, n):
    """
    Add n years to a date d.

    If the resulting day does not exist (e.g., Feb 29 on a non-leap year),
    clamp to Feb 28 of that year. Otherwise, keep the same month and day.

    Note: The function accepts datetime.date objects.
    """
    try:
        return d + relativedelta(years=n)
    except ValueError:
        # This handles the case where adding years results in an invalid date
        # (e.g., Feb 29 -> Mar 1 in a non-leap year)
        # We clamp to the previous day of the target month
        try:
            # Attempt to construct the clamped date manually
            year = d.year + n
            # Find the last day of the month for the target year
            if d.month == 2:
                return date(year, 2, 28)
            else:
                # For other months, the day exists, so just return it
                return date(year, d.month, d.day)
        except Exception:
            raise
