def add_one_month(d: date) -> date:
    year = d.year
    month = d.month + 1

    if month > 12:
        year += 1
        month = 1

    # Try to create the date with the same day
    try:
        return date(year, month, d.day)
    except ValueError:
        # If the day doesn't exist in the target month, clamp to the last day
        # We can do this by creating a date for the 1st of the next month
        # and subtracting one day
        next_month_date = date(year, month + 1, 1) if month < 12 else date(year + 1, 1, 1)
        return next_month_date - timedelta(days=1)
