from datetime import datetime
from zoneinfo import ZoneInfo, available_timezones

def meeting_in_zones(naive_ny, zones):
    ny_tz = ZoneInfo('America/New_York')
    ny_aware = ny_tz.localize(naive_ny)
    results = {}
    for zone_name in zones:
        if zone_name in available_timezones():
            zone_tz = ZoneInfo(zone_name)
            meeting_in_zone = ny_aware.astimezone(zone_tz)
            results[zone_name] = meeting_in_zone.strftime('%Y-%m-%d %H:%M')
        else:
            raise ValueError(f"Unknown timezone: {zone_name}")
    return results
```

